{
  "type": "CODE_BUILDER",
  "lessonText": "Learn how to implement game logic and handle user input in your first Python game.",
  "data": {
    "codeBuilder": {
      "avatarInstruction": "Fill in the missing parts to complete the game loop and user input handling.",
      "lines": [
        {
          "content": "while running:"
        },
        {
          "content": "    for event in pygame.event.get():"
        },
        {
          "content": "        if event.type == pygame.QUIT:"
        },
        {
          "content": "            running = False"
        },
        {
          "content": "    keys = pygame.key.get_pressed()"
        },
        {
          "content": "    if keys[pygame.K_LEFT]:"
        },
        {
          "content": "        player.move_left()"
        },
        {
          "content": "    if keys[pygame.K_RIGHT]:"
        },
        {
          "content": "        player.move_right()"
        },
        {
          "content": "    update_game_state()"
        },
        {
          "content": "    render()"
        }
      ],
      "options": [
        "Implement game loop",
        "Handle user input",
        "Update game state",
        "Render graphics"
      ]
    }
  }
}
